import React, { useState } from "react";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../../common/InputText";
import StickyBox from "react-sticky-box";
import DashboardSidebar from "../sidebar/sidebar.jsx";
import AuthService from "../../../services/auth.service";
import UserService from "../../../services/user.service";
import AlertDismissible from "../../../../common/AlertDismissible";
function Password() {
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState();
  const [status, setStatus] = useState(false);

  const validate = async (values) => {
    const errors = {};
    if (!values.oldPassword) {
      errors.oldPassword = "Required";
    }
    if (!values.newPassword) {
      errors.newPassword = "Required";
    }
    if (!values.confirm) {
      errors.confirm = "Required";
    } else if (values.confirm !== values.newPassword) {
      errors.confirm = "Must match";
    }
    return errors;
  };

  const onSubmit = async (values) => {
    setStatus(false);
    setIsLoading(true);
    const response = await AuthService.login(
      AuthService.getCurrentUser().email,
      values.oldPassword
    );
    setMessage(!!response.message && response.message);
    if (!response.success) {
      setIsLoading(false);
      return;
    }

    if (response.success) {
      const responseChangePassword = await UserService.updateUser({
        password: values.newPassword,
      });

      if (!responseChangePassword.success) {
        setMessage(
          !!responseChangePassword.message && responseChangePassword.message
        );
      } else setStatus(responseChangePassword.success);
    }

    setIsLoading(false);
  };

  return (
    <div>
      <div className="content">
        <div className="container-fluid">
          <div className="row">
            <div className="col-md-5 col-lg-4 col-xl-3 theiaStickySidebar">
              <StickyBox offsetTop={20} offsetBottom={20}>
                <DashboardSidebar />
              </StickyBox>
            </div>

            <div className="col-md-7 col-lg-8 col-xl-9">
              {status ? (
                <AlertDismissible
                  type={"success"}
                  boldMsg={"Success!"}
                  msg={"Password has been changed successfully!"}
                />
              ) : (
                ""
              )}
              <div className="card">
                <div className="card-body">
                  <Form
                    validate={validate}
                    onSubmit={onSubmit}
                    render={({
                      handleSubmit,
                      submitError,
                      form,
                      submitting,
                      pristine,
                      values,
                      reset
                    }) => (
                      <form
                        onSubmit={(event) => {
                          handleSubmit(event).then(reset);
                        }}
                        className="needs-validation"
                        noValidate
                      >
                        {message?.map((m, i) => (
                          <div
                            key={i}
                            className="invalid-feedback d-block mb-2"
                          >
                            {m}
                          </div>
                        ))}
                        <div className="form-group">
                          <label>Old Password</label>
                          <Field
                            name="oldPassword"
                            className="form-control floating"
                            type="password"
                            component={InputField}
                          />
                        </div>
                        <div className="form-group">
                          <label>New Password</label>
                          <Field
                            name="newPassword"
                            className="form-control floating"
                            type="password"
                            component={InputField}
                          />
                        </div>
                        <div className="form-group">
                          <label>Confirm Password</label>
                          <Field
                            name="confirm"
                            className="form-control floating"
                            type="password"
                            component={InputField}
                          />
                        </div>
                        <div className="submit-section">
                          <button
                            type="submit"
                            className="btn btn-primary submit-btn"
                            disabled={isLoading}
                          >
                            {!isLoading ? `Save Changes` : ""}
                            {isLoading && (
                              <span className="spinner-border spinner-border-sm mb-1"></span>
                            )}
                          </button>
                        </div>
                      </form>
                    )}
                  />
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Password;
